mapper.select:
SELECT si.chinese_name AS studentName, si.id AS studentId, sc.class_name AS className, gg.grade_group_name AS gradeGroupName, si.student_no AS studentNo FROM sys_class sc INNER JOIN student_info si ON sc.id = si.class_id LEFT JOIN grade_group gg ON sc.grade_group = gg.id LEFT JOIN activity_student_report asr ON (si.id = asr.student_id AND asr.deleted = 0 AND asr.activity_id = #{req.activityId}) WHERE sc.deleted = 0 AND si.deleted = 0 AND sc.school_id = #{req.schoolId} AND sc.sid = #{req.schoolYear} AND sc.department = #{req.department}
AND sc.id = #{req.classId}
AND si.chinese_name LIKE CONCAT('%', #{req.studentName}, '%')
AND si.student_no LIKE CONCAT('%', #{req.studentNo}, '%')
AND si.class_id IN
#{item}
GROUP BY studentId HAVING COUNT(asr.id) = 0 ORDER BY sc.class_name

SELECT asr.id, si.chinese_name AS studentName, sc.class_name AS className, gg.grade_group_name AS gradeGroupName, si.student_no AS studentNo, asr.volunteer_type AS volunteerType, asr.status, si.id AS studentId, asr.type FROM sys_class sc left JOIN student_info si ON sc.id = si.class_id left JOIN grade_group gg ON sc.grade_group = gg.id left JOIN activity_student_report asr ON si.id = asr.student_id AND asr.activity_id = #{req.activityId} WHERE sc.deleted = 0 AND si.deleted = 0 AND asr.deleted = 0 AND sc.school_id = #{req.schoolId} AND sc.sid = #{req.schoolYear} AND sc.department = #{req.department} AND asr.lenson_id = #{req.lensonId}
AND sc.id = #{req.classId}
AND si.chinese_name LIKE CONCAT('%', #{req.studentName}, '%')
AND si.student_no LIKE CONCAT('%', #{req.studentNo}, '%')
AND asr.type = #{req.selectType}
AND asr.status = #{req.status}
ORDER BY sc.class_name
